,p_static_id=>'emergency-call-kpi-cards'
,p_title=>'Emergency Call Summary'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2074200852440250129
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select card_title, card_value, card_subtitle, icon_css',
'from (',
'  select 10 display_order, ''Today''''s Calls'' card_title, to_char(count(*)) card_value, ''All calls received today'' card_subtitle, ''fa-phone'' icon_css',
'    from emergency_call',
'   where trunc(call_time) = trunc(sysdate)',
'  union all',
'  select 20, ''Pending Calls'', to_char(count(*)), ''Waiting to be dispatched'', ''fa-clock-o''',
'    from emergency_call ec',
'   where not exists (select 1 from dispatch d where d.call_id = ec.call_id)',
'  union all',
'  select 30, ''Dispatched'', to_char(count(distinct d.call_id)), ''Already dispatched'', ''fa-check-circle''',
'    from dispatch d',
'  union all',
'  select 40, ''Cancelled'', ''0'', ''Cancelled calls'', ''fa-times-circle''',
'    from sys.dual',
')',
'order by display_order'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
