,p_plug_name=>'KPI Cards'
,p_static_id=>'kpi-cards'
,p_title=>'Dashboard Summary'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2074200852440250129
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select card_title, card_value, card_subtitle, icon_css',
'from (',
'  select 10 display_order, ''Total Emergency Calls'' card_title, to_char(count(*)) card_value, ''All time'' card_subtitle, ''fa-phone'' icon_css from emergency_call',
'  union all select 20, ''Total Ambulances'', to_char(count(*)), ''All time'', ''fa-ambulance'' from ambulance',
'  union all select 30, ''Available Ambulances'', to_char(count(*)), ''Ready to respond'', ''fa-check-circle'' from ambulance where upper(ambulance_status) like ''%AVAILABLE%''',
'  union all select 40, ''Total Staff'', to_char(count(*)), ''All staff'', ''fa-users'' from staff',
'  union all select 50, ''Total Patients'', to_char(count(*)), ''All time'', ''fa-user'' from patient',
'  union all select 60, ''Total Dispatches'', to_char(count(*)), ''All time'', ''fa-paper-plane'' from dispatch',
'  union all select 70, ''Dispatches In Progress'', to_char(count(*)), ''Active now'', ''fa-heartbeat'' from dispatch where upper(status) in (''ASSIGNED'',''IN_PROGRESS'',''IN PROGRESS'')',
'  union all select 80, ''Completed Dispatches'', to_char(count(*)), ''All time'', ''fa-clock-o'' from dispatch where upper(status) = ''COMPLETED''',
')',
'order by display_order'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
,p_created_on=>wwv_flow_imp.dz('20260624221637Z')
,p_updated_on=>wwv_flow_imp.dz('20260624221637Z')
