,p_display_sequence=>70
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--rowHighlightOff'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select alert_type, alert_message, alert_time',
'  from (',
'        select ''Warning'' alert_type, ''Ambulance '' || number_plate || '' is currently marked '' || ambulance_status || ''.'' alert_message, sysdate alert_time',
'          from ambulance',
'         where upper(ambulance_status) like ''%MAINT%''',
'        union all',
'        select ''Info'', ''There are '' || count(*) || '' pending dispatch records.'', sysdate',
'          from dispatch',
'         where upper(status) = ''PENDING''',
'        union all',
'        select ''Info'', ''There are '' || count(*) || '' emergency calls recorded today.'', sysdate',
'          from emergency_call',
'         where trunc(call_time) = trunc(sysdate)',
'       )',
' where rownum <= 10'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
